    "\u05d5\u05db\u05dc\u05dc \u05d0\u05e8\u05d1\u05e2 \u05d0\u05de\u05d5\u05ea \u05dc\u05d0 \u05d7\u05dc (\u05de\u05e9\u05e0\u05d4 \u05d1\u05e8\u05d5\u05e8\u05d4 \u05d3:\u05dc\"\u05d3)\n"
