    "\u2022 \u05d0\u05dc \u05ea\u05d9\u05d2\u05e2\u05d5 \u05d1\u05d0\u05d5\u05db\u05dc \u05dc\u05e4\u05e0\u05d9 \u05d4\u05e9\u05d8\u05d9\u05e4\u05d4\n"
